+    }
+    let da = unsafe { *a };
+    let db = unsafe { *b };
+    if da.is_null() || db.is_null() {
+        return 0;
+    }
+    let na = unsafe { &(*da).d_name };
+    let nb = unsafe { &(*db).d_name };
+    for i in 0..na.len().min(nb.len()) {
+        let ca = na[i] as u8;
+        let cb = nb[i] as u8;
+        if ca != cb {
+            return (ca as c_int) - (cb as c_int);
